using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly EvaluationMetrics _metrics;
    private readonly ILogger<ChurnModelService> _logger;

    public ITransformer Model => _model;
    public DataViewSchema Schema { get; }
    public EvaluationMetrics Metrics => _metrics;

    public ChurnModelService(ILogger<ChurnModelService> logger)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
        if (!File.Exists(dataPath))
        {
            // Fall back to project-relative path for development
            dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "customers.csv");
        }

        var rawData = _mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        Schema = rawData.Schema;

        // Map "Yes"/"No" string to boolean Label column
        var labelKeys = new[] { "Yes", "No" };
        var labelValues = new[] { true, false };

        var labelPipeline = _mlContext.Transforms.Conversion.MapValue(
            "Label", new Dictionary<string, bool>
            {
                { "Yes", true },
                { "No", false }
            },
            "Churned");

        var featurePipeline = _mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(_mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression());

        var fullPipeline = labelPipeline.Append(featurePipeline);

        var split = _mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);

        _model = fullPipeline.Fit(split.TrainSet);

        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.BinaryClassification.Evaluate(predictions);

        _metrics = new EvaluationMetrics
        {
            Accuracy = metrics.Accuracy,
            AUC = metrics.AreaUnderRocCurve,
            F1Score = metrics.F1Score
        };

        _logger.LogInformation("Model trained — Accuracy: {Accuracy:F4}, AUC: {AUC:F4}, F1: {F1:F4}",
            _metrics.Accuracy, _metrics.AUC, _metrics.F1Score);
    }

    public ChurnPrediction Predict(CustomerData input)
    {
        var engine = _mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(_model);
        return engine.Predict(input);
    }
}

