using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<ChurnModelService>();
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromModel(sp =>
    {
        var service = sp.GetRequiredService<ChurnModelService>();
        return service.Model;
    });

var app = builder.Build();

// Warm up the model on startup
app.Services.GetRequiredService<ChurnModelService>();

app.MapGet("/", (ChurnModelService service) =>
    Results.Json(service.Metrics));

app.MapPost("/predict", (CustomerData input, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Json(prediction);
});

app.Run();

