using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

// Train and save model first
builder.Services.AddSingleton<ChurnModelService>();

var app = builder.Build();

// Trigger model training on startup
var modelService = app.Services.GetRequiredService<ChurnModelService>();

// Now build a second app with PredictionEnginePool pointing at the saved model
// Actually, re-register after model is saved — but since we're using minimal API,
// use the service directly for predictions (it creates engines per-call).
// For thread safety in production, use PredictionEnginePool via a second host or
// register after training. Here we use the service's Predict method.

app.MapGet("/", (ChurnModelService service) =>
    Results.Json(service.Metrics));

app.MapPost("/predict", (CustomerData input, ChurnModelService service) =>
{
    var prediction = service.Predict(input);
    return Results.Json(prediction);
});

app.Run();

