builder.Services.AddSingleton<Microsoft.Extensions.Options.IOptionsFactory<PredictionEnginePoolOptions<CustomerData, ChurnPrediction>>>(sp =>
    new ChurnPredictionEnginePoolOptionsFactory(sp));

