internal class ChurnPredictionEnginePoolOptionsFactory
    : Microsoft.Extensions.Options.IOptionsFactory<PredictionEnginePoolOptions<CustomerData, ChurnPrediction>>
{
    private readonly IServiceProvider _sp;

    public ChurnPredictionEnginePoolOptionsFactory(IServiceProvider sp) => _sp = sp;

    public PredictionEnginePoolOptions<CustomerData, ChurnPrediction> Create(string name)
    {
        var service = _sp.GetRequiredService<ChurnModelService>();
        return new PredictionEnginePoolOptions<CustomerData, ChurnPrediction>
        {
            ModelLoader = new FileModelLoader(service.ModelPath)
        };
    }
}

