using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelService
{
    public string ModelPath { get; }
    public EvaluationMetrics Metrics { get; }

    private ChurnModelService(string modelPath, EvaluationMetrics metrics)
    {
        ModelPath = modelPath;
        Metrics = metrics;
    }

    public static ChurnModelService TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
        if (!File.Exists(dataPath))
            dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "customers.csv");

        var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        var inputSchema = rawData.Schema;

        // Map "Yes"/"No" to boolean Label
        var labelPipeline = mlContext.Transforms.Conversion.MapValue(
            "Label", new Dictionary<string, bool>
            {
                { "Yes", true },
                { "No", false }
            },
            "Churned");

        var featurePipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression());

        var fullPipeline = labelPipeline.Append(featurePipeline);

        var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);
        var model = fullPipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var evalMetrics = mlContext.BinaryClassification.Evaluate(predictions);

        var metrics = new EvaluationMetrics
        {
            Accuracy = evalMetrics.Accuracy,
            AUC = evalMetrics.AreaUnderRocCurve,
            F1Score = evalMetrics.F1Score
        };

        Console.WriteLine($"Model trained — Accuracy: {metrics.Accuracy:F4}, AUC: {metrics.AUC:F4}, F1: {metrics.F1Score:F4}");

        var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
        mlContext.Model.Save(model, inputSchema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        return new ChurnModelService(modelPath, metrics);
    }
}

